/*!
 * Chart.js minimal v4 compatible — FinancesPro offline build
 * Supporte: doughnut, bar, line
 */
(function(global){
'use strict';

function Chart(ctx, config) {
  if (typeof ctx === 'string') ctx = document.getElementById(ctx);
  if (ctx && ctx.getContext) ctx = ctx.getContext('2d');
  this.ctx = ctx;
  this.canvas = ctx ? ctx.canvas : null;
  this.config = config || {};
  this.data = config.data || {};
  this._drawn = false;
  var self = this;
  if (ctx) {
    setTimeout(function(){ self._draw(); }, 0);
  }
}

Chart.prototype.destroy = function() {
  if (this.canvas) {
    var ctx = this.canvas.getContext('2d');
    ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
  }
  this._drawn = false;
};

Chart.prototype._draw = function() {
  var c = this.config;
  var type = c.type;
  if (type === 'doughnut') this._drawDoughnut();
  else if (type === 'bar') this._drawBar();
  else if (type === 'line') this._drawLine();
  this._drawn = true;
};

Chart.prototype._drawDoughnut = function() {
  var ctx = this.ctx;
  if (!ctx || !ctx.canvas) return;
  var W = ctx.canvas.width || 300, H = ctx.canvas.height || 300;
  ctx.clearRect(0, 0, W, H);
  var ds = (this.data.datasets || [])[0] || {};
  var vals = ds.data || [];
  var colors = ds.backgroundColor || ['#34d987','#638cff','#f4c55a','#ffab5e','#8ab4f8','#ff6b6b','#c084fc'];
  var labels = this.data.labels || [];
  var total = vals.reduce(function(a,b){ return a+(b||0); }, 0);
  if (!total) return;
  var cx = W/2, cy = H*0.42, r = Math.min(W,H)*0.32, ri = r*0.55;
  var angle = -Math.PI/2;
  for (var i=0; i<vals.length; i++) {
    var slice = (vals[i]||0)/total * Math.PI*2;
    ctx.beginPath();
    ctx.moveTo(cx, cy);
    ctx.arc(cx, cy, r, angle, angle+slice);
    ctx.closePath();
    ctx.fillStyle = colors[i % colors.length];
    ctx.fill();
    ctx.beginPath();
    ctx.arc(cx, cy, ri, 0, Math.PI*2);
    ctx.fillStyle = '#1a2238';
    ctx.fill();
    angle += slice;
  }
  // Légende
  var opts = (this.config.options||{}).plugins||{};
  var legOpts = opts.legend || {};
  if (legOpts.display !== false) {
    var legColor = (legOpts.labels||{}).color || '#8fa3cc';
    var legPad = (legOpts.labels||{}).padding || 8;
    var legFont = (legOpts.labels||{}).font || {};
    var fontSize = legFont.size || 11;
    ctx.font = fontSize+'px system-ui,sans-serif';
    ctx.textBaseline = 'middle';
    var legY = cy + r + 20;
    var boxW = 12, gap = 6;
    var itemW = 90;
    var perRow = Math.max(1, Math.floor(W / (itemW + legPad)));
    for (var j=0; j<labels.length && j<vals.length; j++) {
      var col = j % perRow;
      var row = Math.floor(j / perRow);
      var lx = (W - perRow*(itemW+legPad))/2 + col*(itemW+legPad);
      var ly = legY + row*22;
      ctx.fillStyle = colors[j % colors.length];
      ctx.fillRect(lx, ly-6, boxW, 12);
      ctx.fillStyle = legColor;
      var lbl = (labels[j]||'').substring(0,12);
      ctx.fillText(lbl, lx+boxW+gap, ly);
    }
  }
};

Chart.prototype._drawBar = function() {
  var ctx = this.ctx;
  if (!ctx || !ctx.canvas) return;
  var W = ctx.canvas.width || 400, H = ctx.canvas.height || 280;
  ctx.clearRect(0, 0, W, H);
  var datasets = this.data.datasets || [];
  var labels = this.data.labels || [];
  var opts = this.config.options || {};
  var scales = opts.scales || {};
  var yOpts = scales.y || {};
  var tickCb = ((yOpts.ticks||{}).callback) || function(v){ return v; };
  var xTickColor = ((scales.x||{}).ticks||{}).color || '#5a6e94';
  var yTickColor = ((yOpts.ticks)||{}).color || '#5a6e94';
  var pad = {l:52, r:12, t:16, b:36};
  var bW = W - pad.l - pad.r;
  var bH = H - pad.t - pad.b;
  var allVals = [];
  datasets.forEach(function(ds){ (ds.data||[]).forEach(function(v){ allVals.push(v||0); }); });
  var maxV = Math.max.apply(null, allVals.concat([1]));
  var nGroups = labels.length;
  var nDS = datasets.length;
  var groupW = bW / Math.max(nGroups,1);
  var barW = groupW / (nDS+1) * 0.9;
  // Axes
  ctx.strokeStyle = '#2a3550'; ctx.lineWidth = 1;
  ctx.beginPath(); ctx.moveTo(pad.l, pad.t); ctx.lineTo(pad.l, pad.t+bH); ctx.lineTo(pad.l+bW, pad.t+bH); ctx.stroke();
  // Y ticks
  var nTicks = 4;
  ctx.font = '10px system-ui'; ctx.fillStyle = yTickColor; ctx.textAlign = 'right'; ctx.textBaseline = 'middle';
  for (var t=0; t<=nTicks; t++) {
    var v = maxV * t / nTicks;
    var ty = pad.t + bH - (bH * t / nTicks);
    ctx.fillText(tickCb(v), pad.l-4, ty);
    ctx.strokeStyle='rgba(255,255,255,0.05)'; ctx.beginPath(); ctx.moveTo(pad.l, ty); ctx.lineTo(pad.l+bW, ty); ctx.stroke();
  }
  // Bars + X labels
  ctx.textAlign = 'center'; ctx.textBaseline = 'top';
  for (var g=0; g<nGroups; g++) {
    var gx = pad.l + g*groupW + groupW/2;
    ctx.fillStyle = xTickColor;
    ctx.font = '10px system-ui';
    ctx.fillText(labels[g]||'', gx, pad.t+bH+4);
    for (var d=0; d<nDS; d++) {
      var ds2 = datasets[d];
      var val = (ds2.data||[])[g] || 0;
      var bx = pad.l + g*groupW + (d+0.5)*barW + barW*0.1;
      var bh = bH * val / maxV;
      var by = pad.t + bH - bh;
      ctx.fillStyle = Array.isArray(ds2.backgroundColor) ? ds2.backgroundColor[g]||(ds2.backgroundColor[0]||'#638cff') : (ds2.backgroundColor||'#638cff');
      var br = (ds2.borderRadius||4);
      ctx.beginPath();
      ctx.moveTo(bx+br, by); ctx.lineTo(bx+barW-br, by);
      ctx.arcTo(bx+barW, by, bx+barW, by+br, br);
      ctx.lineTo(bx+barW, by+bh); ctx.lineTo(bx, by+bh);
      ctx.arcTo(bx, by, bx+br, by, br);
      ctx.closePath();
      ctx.fill();
    }
  }
  // Légende
  var legOpts2 = ((opts.plugins||{}).legend||{});
  if (legOpts2.display !== false) {
    var legColor2 = ((legOpts2.labels||{}).color)||'#8fa3cc';
    ctx.font = '11px system-ui'; ctx.textAlign = 'left'; ctx.textBaseline = 'middle';
    var lx0 = pad.l;
    datasets.forEach(function(ds3, i) {
      ctx.fillStyle = Array.isArray(ds3.borderColor) ? ds3.borderColor[0] : (ds3.borderColor||'#638cff');
      ctx.fillRect(lx0, 4, 12, 10);
      ctx.fillStyle = legColor2;
      ctx.fillText(ds3.label||'', lx0+15, 9);
      lx0 += (ds3.label||'').length * 7 + 30;
    });
  }
};

Chart.prototype._drawLine = function() {
  var ctx = this.ctx;
  if (!ctx || !ctx.canvas) return;
  var W = ctx.canvas.width || 400, H = ctx.canvas.height || 200;
  ctx.clearRect(0, 0, W, H);
  var datasets = this.data.datasets || [];
  var labels = this.data.labels || [];
  var opts = this.config.options || {};
  var scales = opts.scales || {};
  var yOpts = scales.y || {};
  var maxOpt = ((yOpts)||{}).max;
  var tickCb = ((yOpts.ticks||{}).callback) || function(v){ return v; };
  var xTickColor = ((scales.x||{}).ticks||{}).color || '#5a6e94';
  var yTickColor = ((yOpts.ticks)||{}).color || '#5a6e94';
  var pad = {l:52, r:12, t:16, b:36};
  var bW = W-pad.l-pad.r, bH = H-pad.t-pad.b;
  var allVals = [];
  datasets.forEach(function(ds){ (ds.data||[]).forEach(function(v){ allVals.push(v||0); }); });
  var maxV = maxOpt || Math.max.apply(null, allVals.concat([1]));
  var nPts = labels.length;
  // Axes
  ctx.strokeStyle='#2a3550'; ctx.lineWidth=1;
  ctx.beginPath(); ctx.moveTo(pad.l,pad.t); ctx.lineTo(pad.l,pad.t+bH); ctx.lineTo(pad.l+bW,pad.t+bH); ctx.stroke();
  // Y ticks
  var nTicks=4;
  ctx.font='10px system-ui'; ctx.fillStyle=yTickColor; ctx.textAlign='right'; ctx.textBaseline='middle';
  for (var t=0; t<=nTicks; t++) {
    var v=maxV*t/nTicks, ty=pad.t+bH-(bH*t/nTicks);
    ctx.fillText(tickCb(v), pad.l-4, ty);
    ctx.strokeStyle='rgba(255,255,255,0.05)'; ctx.beginPath(); ctx.moveTo(pad.l,ty); ctx.lineTo(pad.l+bW,ty); ctx.stroke();
  }
  // X labels
  ctx.fillStyle=xTickColor; ctx.textAlign='center'; ctx.textBaseline='top';
  for (var g=0; g<nPts; g++) {
    var gx=pad.l+(g/(Math.max(nPts-1,1)))*bW;
    ctx.fillText(labels[g]||'', gx, pad.t+bH+4);
  }
  // Lines
  datasets.forEach(function(ds) {
    var pts = ds.data||[];
    var color = Array.isArray(ds.borderColor)?ds.borderColor[0]:(ds.borderColor||'#638cff');
    var bgColor = ds.backgroundColor || 'rgba(99,140,255,0.1)';
    // Fill
    if (ds.fill) {
      ctx.beginPath();
      for (var i=0; i<pts.length; i++) {
        var px=pad.l+(i/(Math.max(pts.length-1,1)))*bW;
        var py=pad.t+bH-(bH*(pts[i]||0)/maxV);
        if(i===0) ctx.moveTo(px,py); else ctx.lineTo(px,py);
      }
      ctx.lineTo(pad.l+bW, pad.t+bH); ctx.lineTo(pad.l, pad.t+bH); ctx.closePath();
      ctx.fillStyle=bgColor; ctx.fill();
    }
    // Line
    ctx.beginPath(); ctx.strokeStyle=color; ctx.lineWidth=2;
    for (var i=0; i<pts.length; i++) {
      var px=pad.l+(i/(Math.max(pts.length-1,1)))*bW;
      var py=pad.t+bH-(bH*(pts[i]||0)/maxV);
      if(i===0) ctx.moveTo(px,py); else ctx.lineTo(px,py);
    }
    ctx.stroke();
    // Points
    var ptBg = ds.pointBackgroundColor || color;
    for (var i=0; i<pts.length; i++) {
      var px=pad.l+(i/(Math.max(pts.length-1,1)))*bW;
      var py=pad.t+bH-(bH*(pts[i]||0)/maxV);
      ctx.beginPath(); ctx.arc(px,py,3,0,Math.PI*2);
      ctx.fillStyle=ptBg; ctx.fill();
    }
  });
};

Chart.register = function(){};
Chart.defaults = { color: '#8fa3cc', font: { family: 'system-ui' } };

if (typeof module !== 'undefined' && module.exports) { module.exports = Chart; }
else { global.Chart = Chart; }

})(typeof window !== 'undefined' ? window : this);
